SELECT h.provider_name AS facility_name, h.total_beds, COALESCE(f.total_occupied_beds, 0) AS total_occupied_beds
FROM healthcare_facilities h
LEFT JOIN facility_capacity f ON h.facility_id = f.facility_id;

SELECT h.facility_id, h.provider_name, h.total_beds, fc.available_beds, fc.icu_beds, (fc.available_beds + (fc.icu_beds * 2)) AS total_available_beds
FROM healthcare_facilities h
JOIN facility_capacity fc ON h.facility_id = fc.facility_id;

SELECT hf.provider_name, hf.phone_number
FROM healthcare_facilities hf
WHERE hf.total_beds > (SELECT AVG(total_beds) FROM healthcare_facilities);

SELECT facility_id, available_beds
FROM facility_capacity
WHERE available_beds = (
    SELECT MAX(available_beds)
    FROM facility_capacity
);

SELECT facility_id, total_beds AS TotalBeds
FROM healthcare_facilities
ORDER BY TotalBeds DESC;

SELECT f.provider_name, f.total_beds
FROM healthcare_facilities f
WHERE f.total_beds > (SELECT AVG(total_beds) FROM healthcare_facilities);

SELECT 
    (SELECT SUM(total_confirmed) FROM covid_data_residents WHERE facility_id = 1) AS total_confirmed_residents,
    (SELECT SUM(total_confirmed) FROM covid_data_staff WHERE facility_id = 1) AS total_confirmed_staff;

SELECT facility_id, AVG(EXP(total_confirmed)) as Average_Exponential_Confirmed_Cases
FROM covid_data_residents
GROUP BY facility_id;

SELECT h.city, h.county, s.name, s.department
FROM healthcare_facilities AS h
LEFT JOIN state_health_officials AS s ON 1=1;

SELECT COUNT(official_id) 
FROM state_health_officials
WHERE department = 'Public Health';
